class Solution:
    def findKthSmallest(self, coins, k: int) -> int:
        from math import gcd
        def lcm(a, b):
            return a * b // gcd(a, b)
        n = len(coins)
        def count_le(x):
            # inclusion-exclusion over all non-empty subsets
            total = 0
            for mask in range(1, 1 << n):
                l = 1
                bits = 0
                for i in range(n):
                    if mask >> i & 1:
                        l = lcm(l, coins[i])
                        bits += 1
                        if l > x:
                            break
                else:
                    total += (x // l) * (1 if bits % 2 == 1 else -1)
            return total
        lo, hi = 1, coins[0] * k
        while lo < hi:
            mid = (lo + hi) // 2
            if count_le(mid) >= k:
                hi = mid
            else:
                lo = mid + 1
        return lo

