class Solution:
    def findKthSmallest(self, coins, k: int) -> int:
        from math import gcd
        def lcm(a, b): return a * b // gcd(a, b)
        n = len(coins)
        # Precompute subset LCMs
        subsets = []  # (lcm_val, parity) where parity=+1 or -1
        for mask in range(1, 1 << n):
            l = 1
            bits = 0
            ok = True
            for i in range(n):
                if mask >> i & 1:
                    l = lcm(l, coins[i])
                    bits += 1
                    if l > 2 * 10**13:  # cap: no multiples within range
                        ok = False
                        break
            if ok:
                subsets.append((l, 1 if bits % 2 == 1 else -1))
        def count_le(x):
            return sum(sign * (x // l) for l, sign in subsets)
        lo, hi = min(coins), min(coins) * k
        while lo < hi:
            mid = (lo + hi) // 2
            if count_le(mid) >= k:
                hi = mid
            else:
                lo = mid + 1
        return lo

