var findKthSmallest = function(coins, k) {
    function gcd(a, b) { while (b) { [a, b] = [b, a % b]; } return a; }
    function lcm(a, b) { return a / gcd(a, b) * b; }
    const n = coins.length;
    const subsets = [];
    for (let mask = 1; mask < (1 << n); mask++) {
        let l = 1, bits = 0, ok = true;
        for (let i = 0; i < n; i++) {
            if (mask >> i & 1) {
                l = lcm(l, coins[i]);
                bits++;
                if (l > 2e13) { ok = false; break; }
            }
        }
        if (ok) subsets.push([l, bits % 2 === 1 ? 1 : -1]);
    }
    function countLe(x) {
        let total = 0;
        for (const [l, sign] of subsets) total += sign * Math.floor(x / l);
        return total;
    }
    let lo = Math.min(...coins), hi = lo * k;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (countLe(mid) >= k) hi = mid;
        else lo = mid + 1;
    }
    return lo;
};
